cat /Users/4thwithme/.claude/projects/-Users-4thwithme-Documents-repo-recommendations-service/8eef2335-2d26-47a3-a65e-af87432cb8d2/tool-results/b5cpf47hd.txt | python3 -c "
import json, sys
data = json.load(sys.stdin)
merged = [pr for pr in data if pr['state'] == 'MERGED']
print(f'Merged PRs: {len(merged)}')
print(f'Closed (not merged): {len([pr for pr in data if pr[\"state\"] == \"CLOSED\"])}')
print(f'Open: {len([pr for pr in data if pr[\"state\"] == \"OPEN\"])}')
print()

# Categorize
categories = {
    'ESLint/Code Quality': [],
    'Bug Fixes': [],
    'New Features': [],
    'CI/CD & DevOps': [],
    'AI/ML & Claude Code': [],
    'Performance & Optimization': [],
    'Monitoring & Observability': [],
    'Infrastructure & Config': [],
    'Documentation': [],
    'Reverts': [],
}

for pr in merged:
    t = pr['title'].lower()
    if 'eslint' in t or 'lint' in t or 'code-quality' in t or 'require-object-params' in t:
        categories['ESLint/Code Quality'].append(pr['title'])
    elif 'revert' in t:
        categories['Reverts'].append(pr['title'])
    elif 'fix' in t or 'bug' in t or 'hotfix' in t or 'hot fix' in t or 'hot-fix' in t:
        categories['Bug Fixes'].append(pr['title'])
    elif 'claude' in t or 'ai-monkey' in t or 'skill' in t or 'cc ' in t or 'claude code' in t:
        categories['AI/ML & Claude Code'].append(pr['title'])
    elif 'ci' in t or 'circleci' in t or 'autotest' in t or 'pipeline' in t or 'workflow' in t:
        categories['CI/CD & DevOps'].append(pr['title'])
    elif 'rollbar' in t or 'newrelic' in t or 'monitor' in t or 'log' in t:
        categories['Monitoring & Observability'].append(pr['title'])
    elif 'promo' in t or 'feature' in t or 'backend' in t or 'endpoint' in t or 'trending' in t or 'neural' in t or 'algolia' in t:
        categories['New Features'].append(pr['title'])
    elif 'performance' in t or 'optim' in t or 'shrink' in t or 'timeout' in t or 'resource' in t or 'connection' in t:
        categories['Performance & Optimization'].append(pr['title'])
    elif 'npm' in t or 'config' in t or 'env' in t or 'pre-push' in t or 'swagger' in t:
        categories['Infrastructure & Config'].append(pr['title'])
    elif 'doc' in t or 'uml' in t or 'readme' in t or 'claude.md' in t:
        categories['Documentation'].append(pr['title'])
    else:
        # Try to recategorize
        body = (pr.get('body') or '').lower()
        if 'eslint' in body:
            categories['ESLint/Code Quality'].append(pr['title'])
        elif 'claude' in body or 'skill' in body:
            categories['AI/ML & Claude Code'].append(pr['title'])
        else:
            categories['Infrastructure & Config'].append(pr['title'])

for cat, prs in categories.items():
    if prs:
        print(f'### {cat} ({len(prs)} PRs)')
        for p in prs:
            print(f'  - {p}')
        print()
" 2>&1

